mapper.select:
SELECT a.*,t.name AS subjectTypeName,c.name AS categoryName,d.value AS difficultyName 
FROM subject a,subject_type t,category c,dictionary d 
WHERE a.subject_type_id = t.id AND a.category_id = c.id AND a.difficulty = d.id

    AND a.name LIKE CONCAT('%',#{name},'%')


    AND a.subject_type_id = #{subjectTypeId}


    AND a.category_id = #{categoryId}


    AND a.difficulty = #{difficulty}


    AND (a.company_id = #{judgeId} or a.org_id = #{judgeId})

order by updated_time DESC

SELECT a.*,t.name AS subjectTypeName,c.name AS categoryName,d.value AS difficultyName
FROM subject a,subject_type t,category c,dictionary d
WHERE a.subject_type_id = t.id AND a.category_id = c.id AND a.difficulty = d.id

    AND a.category_id = #{subject.categoryId}


    AND a.name LIKE CONCAT('%',#{subject.name},'%')


    AND a.subject_type_id = #{subject.subjectTypeId}


    AND a.difficulty = #{subject.difficulty}


    AND (a.company_id = #{subject.judgeId} or a.org_id = #{subject.judgeId})

order by updated_time DESC

SELECT a.*,t.name AS subjectTypeName,c.name AS categoryName,d.value AS difficultyName
FROM subject a,subject_type t,category c,dictionary d
WHERE a.subject_type_id = t.id AND a.category_id = c.id AND a.difficulty = d.id

    AND a.category_id IN

        #{catId}



    AND a.name LIKE CONCAT('%',#{subject.name},'%')


    AND a.subject_type_id = #{subject.subjectTypeId}


    AND a.difficulty = #{subject.difficulty}


    AND (a.company_id = #{subject.judgeId} or a.org_id = #{subject.judgeId})

order by updated_time DESC

SELECT a.id 
FROM subject a
Left JOIN subject_type t ON a.subject_type_id = t.id
LEFT JOIN category c ON a.category_id = c.id
LEFT JOIN dictionary d ON a.difficulty = d.id 
WHERE a.subject_type_id = #{subjectTypeId} 
AND a.category_id = #{categoryId} 
AND a.difficulty = #{difficulty}
